# Category: use_after_free

#include <iostream>
#include <chrono>
#include <unordered_map>
#include <list>

struct Session {
    std::string id;
    std::string data;
    time_t lastAccessTime;
    Session(std::string id, std::string data) : id(id), data(data), lastAccessTime(time(0)) {}
};

class Cache {
public:
    Cache(size_t maxSize) : _maxSize(maxSize), _cache(), _lru() {}

    void createSession(std::string id, std::string data) {
        if (_cache.find(id) != _cache.end()) {
            invalidateSession(id);
        }
        Session newSession(id, data);
        _cache[id] = newSession;
        _lru.push_back(newSession);
    }

    void accessSession(std::string id) {
        auto it = _cache.find(id);
        if (it != _cache.end()) {
            _lru.erase(_lru.begin());
            _lru.push_back(it->second);
            it->second.lastAccessTime = time(0);
            return;
        }
        std::cerr << "Session not found: " << id << std::endl;
    }

    void invalidateSession(std::string id) {
        auto it = _cache.find(id);
        if (it != _cache.end()) {
            _lru.erase(std::remove(_lru.begin(), _lru.end(), it->second), _lru.end());
            _cache.erase(id);
            delete &it->second;

            if (_cache.size() > _maxSize) {
                auto oldest = _lru.back();
                _lru.pop_back();
                _cache.erase(oldest.id);
                delete &oldest;
            }
        } else {
            std::cerr << "Session not found: " << id << std::endl;
        }
    }

private:
    size_t _maxSize;
    std::unordered_map<std::string, Session> _cache;
    std::list<Session> _lru;
};

int main() {
    Cache cache(10);

    // Create sessions
    cache.createSession("session1", "data1");
    cache.createSession("session2", "data2");
    cache.createSession("session3", "data3");

    // Access sessions
    cache.accessSession("session1");
    cache.accessSession("session4"); // Should invalidate session2 as the cache has reached its max size (10)
    cache.accessSession("session5"); // Should invalidate session1 as it's the oldest session

    return 0;
}